/**
 * Returns the chip-pill display name for a slug in the given locale.
 * Falls back to the English `cfg.genre_name` when no localised value exists.
 */
export function getSlugDisplayName(slug: string, locale: string, fallback: string): string {
  return SLUG_NAME_OVERRIDES[slug]?.[locale] ?? fallback;
}
